sql:
SELECT TSH, T3
FROM lab_tests
WHERE TSH_measured = 't' AND T3_measured = 't';

SELECT COUNT(DISTINCT patient_id) AS total_unique_patients
FROM thyroid_queries
WHERE query_hypothyroid = 't' OR query_hyperthyroid = 't';

SELECT DISTINCT patient_id
FROM lab_tests
WHERE TSH < 2.5 OR TSH > 4.5;

SELECT MIN(p.age) AS youngest_age
FROM patients p
JOIN I131_treatment i ON p.patient_id = i.patient_id;

SELECT COUNT(*) AS sick_patients_count
FROM medical_conditions
WHERE sick = 't';

SELECT patient_id
FROM thyroid_queries
WHERE query_hyperthyroid = 't' AND query_hypothyroid = 't';

SELECT surgery_type, COUNT(surgery_id) AS number_of_surgeries
FROM thyroid_surgery
GROUP BY surgery_type;

SELECT COUNT(DISTINCT patient_id)
FROM thyroid_surgery
WHERE thyroid_surgery = 't';

SELECT COUNT(patient_id) AS num_diabetic_and_sick_patients
FROM medical_conditions
WHERE sick = 't' AND diabetes = 't';

SELECT patient_id
FROM thyroid_queries
WHERE query_hypothyroid = 't';

SELECT age 
FROM patients 
WHERE patient_id = 1;

SELECT DISTINCT patient_id
FROM I131_treatment
WHERE I131_treatment = 't';
